from flask import Flask, request
import psycopg2
app = Flask(__name__)
@app.route('/api', methods=['GET'])
def dynamic_query():
    table_name = request.args.get('table')
    column_names = request.args.getlist('columns[]')
    filters = request.args.get('filters')
    
    conn = psycopg2.connect(database="your_db", user="user", password="pass", host="127.0.0.1", port="5432")
    cur = conn.cursor()

    columns_clause = ', '.join(column_names) if column_names else '*'
    
    query = f"SELECT {columns_clause} FROM {table_name}"
    
    if filters:
        query += f" WHERE {filters}"
        
    cur.execute(query)
    
    result = cur.fetchall()
    conn.close()
    return {'result': str(result)}
if __name__ == '__main__':
    app.run(port=5000, debug=True)